2015     return BinaryOperator::CreateFMulFMF(Op0, Pow, &I);
2016   }
2017   case Intrinsic::exp:
2018   case Intrinsic::exp2:
2019     Args.push_back(Builder.CreateFNegFMF(II->getArgOperand(0), &I));
2020     break;
2021   default:
2022     return nullptr;
2023   }
2024   Value *Pow = Builder.CreateIntrinsic(IID, I.getType(), Args, &I);
